# Flask example: incremental consent pattern
# Scope for sign-in only — no mail access requested at login
from flask import Flask, redirect, session, url_for, request
from msal import ConfidentialClientApplication

app_config = {
    'CLIENT_ID':     '<client-id>',
    'CLIENT_SECRET': '<client-secret>',
    'AUTHORITY':     'https://login.microsoftonline.com/<tenant-id>',
    'REDIRECT_URI':  'https://app.example.com/callback',
    'BASE_SCOPES':   ['openid', 'profile', 'User.Read'],  # always requested
    'MAIL_SCOPES':   ['Mail.Read'],                        # requested on demand
}

def get_msal_app():
    return ConfidentialClientApplication(
        app_config['CLIENT_ID'],
        client_credential=app_config['CLIENT_SECRET'],
        authority=app_config['AUTHORITY'],
    )

flask_app = Flask(__name__)

@flask_app.route('/login')
def login():
    # Step 1: sign in with base scopes only
    flow = get_msal_app().initiate_auth_code_flow(
        scopes=app_config['BASE_SCOPES'],
        redirect_uri=app_config['REDIRECT_URI']
    )
    session['flow'] = flow
    return redirect(flow['auth_uri'])

@flask_app.route('/read-mail')
def read_mail():
    msal_app = get_msal_app()
    accounts = msal_app.get_accounts()
    if accounts:
        # Try silent token acquisition with mail scope
        result = msal_app.acquire_token_silent(
            scopes=app_config['BASE_SCOPES'] + app_config['MAIL_SCOPES'],
            account=accounts[0]
        )
        if result and 'access_token' in result:
            # Got token silently — user already consented to Mail.Read
            return f"Access token (Mail.Read): {result['access_token'][:20]}..."

    # Silent failed — trigger incremental consent for Mail.Read
    # Entra shows consent only for the new scope, not the already-granted ones
    flow = msal_app.initiate_auth_code_flow(
        scopes=app_config['BASE_SCOPES'] + app_config['MAIL_SCOPES'],
        redirect_uri=app_config['REDIRECT_URI']
    )
    session['flow'] = flow
    return redirect(flow['auth_uri'])
